#include <bits/stdc++.h>
using namespace std;
int n,m,a[2003][2003],dp[2003][2003];
//dp[i][j]=选择第i组后j步所需的时间
int main(){
    cin>>n>>m;
    for(int i=1;i<=m;i++)
        for(int j=1;j<=n;j++)cin>>a[i][j];
    int ans=2000000000;
    for(int i=n;i;i--){//枚举后i步
        for(int j=1;j<=m;j++){//枚举第j组
            if(i==n)dp[j][i]=a[j][i];
            else dp[j][i]=min(dp[j][i+1],dp[j+1-(j==m)*m][i+1])+a[j][i];
            if(i==1)ans=min(ans,dp[j][i]);
        }
    }
    cout<<ans;
    return 0;
}
